var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"복수귀, 알레이스터.","JPN":"復讐鬼、アレイスター。","ENG":"The Revenger, Aleister.","TWN":"復仇之鬼，阿萊斯特。"},"stage":{"bg":"SWANSONG_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그게 내가 이 무대에서 정한 배역의 이름이야.","JPN":"それが私がこの舞台で決めた配役の名前だ。","ENG":"That is the name of the role I've given myself for this stage.","TWN":"那是我在這個舞台上定下的角色名字。"},"stage":{"bg":"SWANSONG_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알레이스터……?","JPN":"アレイスター……？","ENG":"Aleister...?","TWN":"阿萊斯特……？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제 포기하게, 카넬리안.","JPN":"ここで諦めたまえ、カーネリアン。","ENG":"Give up, Carnelian.","TWN":"現在放棄吧，卡內利安。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"삼 년 전, 런던에서 발생한 그림자 사태는 다름 아닌 우리의 실책이었어.","JPN":"三年前、ロンドンで発生したシャドウ事変は、他でもない私たちの失敗だった。","ENG":"The Shadow incident in London three years ago was our mistake.","TWN":"三年前，倫敦發生的暗影事件，正是我們的失誤。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"조금만 더 일찍 모든 것을 깨달았다면, 자네의 동생을 구해낼 수 있었을지도 모르지","JPN":"もう少し早くすべてのことに気付いていたなら、君の妹を救うことができたのかもしれない。","ENG":"If we had realized what was happening sooner, we could've saved your sister.","TWN":"如果能早一點察覺到一切，或許還能救出你的妹妹。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이미 소중한 사람을 잃어버린 자네에게는 변명처럼 들릴 지도 몰라.","JPN":"すでに大事な人を失してしまった君には、言い訳にしか聞こえないだろう。","ENG":"I know it might sound like an excuse to someone who had lost someone dear.","TWN":"對於已經失去珍貴之人的你來說，這聽起來可能像是藉口。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 우린 그 사태의 흑막을 밝혀내기 위해 모든 수단을 동원하여 최선을 다했네.","JPN":"だが、私たちはあの事変の黒幕を突き止めるためにあらゆる手段を使って頑張ってきた。","ENG":"But we did our best to uncover who was behind it all.","TWN":"但是為了揭開那次案件的幕後黑手，我們動用了所有手段，盡了最大的努力。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 파트너는 이를 위해, 지난 삼 년간 그의 밑에서 손을 더럽혔어.","JPN":"私のパートナーはそのために、三年間彼の下で手を汚したのだ。","ENG":"And for this, my partner here had gotten his hands dirty for the past three years.","TWN":"我的搭檔為了這個目的，過去三年一直在他手下幹髒活。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티…….","JPN":"モリアーティ……","ENG":"Moriarty...","TWN":"莫里蒂……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 그 사건의 배후에는 모리어티 교수가 있었어.","JPN":"そう。あの事件の裏にはモリアーティ教授がいた。","ENG":"Yes. It was Professor Moriarty who was behind it.","TWN":"是的。那起事件的幕後黑手是莫里蒂教授。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"대체 어째서 그자의 말을 따랐던 거지?","JPN":"いったいどうして彼の指示に従ったのだ？","ENG":"So, why did you choose to follow his orders?","TWN":"到底為什麼要聽那傢伙的話？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그자는 자네의 동생을 마물로 만든 장본인이나 다름이 없을 텐데?","JPN":"あの者は君の妹を魔物にした張本人同然なはずだが。","ENG":"He is the one responsible for turning your sister into a monster.","TWN":"那個人不就是把你妹妹變成怪物的罪魁禍首嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"……나도 알고 있어.","JPN":"……私だってわかっている。","ENG":"...I know.","TWN":"……我也知道這些。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 나의 계시를 실현하기 위해서는 반드시 그자의 협력이 필요했지.","JPN":"でも、私の啓示を実現するためには必ずモリアーティの協力が必要だったんだ。","ENG":"But I needed his help in actualizing my revelation.","TWN":"但是為了實現我得到的啟示，必須要有那個人的協助。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"오히려 그자는 자기 목숨에 대한 집착이 전혀 없었어.","JPN":"むしろ、彼は自分の命にまったく執着していなかった。","ENG":"He had no obsession with his life, after all.","TWN":"那個人反而對自己的生命毫不執著。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。</color>"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 자네도 알고 있을 텐데, 숙적?","JPN":"君もわかっているはずだろう、宿敵？","ENG":"I’m sure you know this too, my nemesis.","TWN":"所以你也明白的，對吧，宿敵？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"내가 진짜 원하는 것은 나의 하찮은 목숨의 보전 따위가 아니라는 걸 말이야.","JPN":"私が本当に望むものとは、たかが自分の命を守るなどのくだらないものではないということを。","ENG":"What I truly want is not preserving my worthless life.","TWN":"我真正想要的並不是保全我這卑微的性命。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그자가 원하는 바는 단 하나.","JPN":"モリアーティの望みはたった一つ。","ENG":"There was only one thing he wanted.","TWN":"那傢伙的願望只有一個。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"이 땅에 <color=#ffd34c>천사</color>를 강림시켜, 황금 새벽을 맞이하는 것.","JPN":"この地に<color=#ffd34c>天使</color>を降臨させて、黄金の暁を迎えること。","ENG":"The descending of an <color=#ffd34c>angel</color> to this world, and welcoming the golden dawn.","TWN":"讓<color=#ffd34c>天使</color>降臨這片土地，迎接黃金黎明。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"오직 그것만이 그자의 법이었지.","JPN":"ただそれだけが、モリアーティの法だった。","ENG":"That was his only law.","TWN":"那就是他唯一的律法。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"의식을 마치면, 그자는 순순히 자기 목숨을 내놓겠다고 하더군.","JPN":"儀式が終われば、彼は素直に自分の命を捧げると言っていたんだ。","ENG":"After completing the ritual, he said that he would willingly give up his life.","TWN":"儀式結束後，他說會乖乖交出自己的性命。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"덕분에 나는 그자의 부와 명예, 조직 그리고 지식을 이용할 수 있었어.","JPN":"おかげで私は彼の富と名誉、組織、そして知識を利用することができた。","ENG":"Thanks to that, I was able to take advantage of his wealth, fame, organization, and knowledge.","TWN":"多虧了他，我才能利用他的財富、名譽、組織和知識。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"동생을 모욕하던 이 썩어빠진 도시에 복수를 이뤄낼 수 있었고.","JPN":"妹を侮辱したこのクソみたいな都市に、復讐することができた。","ENG":"I was able to get my revenge on this rotten city that had insulted my sister.","TWN":"我才能對這個玷污了我妹妹的腐敗之城進行復仇。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"원하는 바를 이루기 위해서 의중을 모르는 적과 손을 잡는 건 안일한 판단이야.","JPN":"念願を叶えるために、相容れない敵と手を組むのは愚かな判断だ。","ENG":"It was reckless to join hands with an enemy whose intentions you don't know in order to achieve your goal.","TWN":"為了達成目標，與心思難測的敵人聯手是輕率的判斷。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 땅에 천사를 강림시키겠다고? 그것이 정말로 천사가 맞긴 한가?","JPN":"この地に天使を降臨させるだと？　それは本当に天使なのか？","ENG":"Descending an angel to this world? Would it even really be an angel?","TWN":"你說要讓天使降臨這片土地？但那真的是天使嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 애초에 이런 엉터리 같은 의식으로 진심으로 그게 가능하다고 생각하나?","JPN":"いや、そもそもこんなデタラメな儀式で、本当にそんなことができると思ってるのか？","ENG":"Better yet, did you really think that a ridiculous ritual like this one would ever be possible?","TWN":"還是說你真的認為這種荒唐的儀式能夠成功？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"이해하지 못해도 상관없어. 당신을 위해 시작한 일이 아니니까.","JPN":"理解できなくたっていい。あんたのために始めたわけじゃないからな。","ENG":"It doesn’t matter if you don't understand. I didn't start this for you.","TWN":"無法理解也沒關係。這不是為了你而開始的。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"계시라고? 속삭임이 들린다고?","JPN":"啓示だと？　ささやきが聞こえるだと？","ENG":"A calling? And you say you hear whispers?","TWN":"你是說那個啟示嗎？你聽到的那些低語？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그게 정말로 자네 동생의 목소리였다면, 자네가 살인마가 되기를 바랬을까?","JPN":"それが本当に君の妹の声だったなら、君に殺人鬼になってほしかったと思うのか？","ENG":"If that truly is your sister's voice, would she have wanted you to become a murderer?","TWN":"好好想想，如果那真是你妹妹的聲音，她會希望你成為殺人魔嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아무 죄 없는 여인들을 살해하고, 그림을 그리는 손에 피가 묻기를 원했겠냐는 말이야.","JPN":"何の罪もない女性たちを殺し、絵を描く手を血に染めることを望んでいたとでも？","ENG":"Killing innocent women and getting blood all over your hands.","TWN":"她會希望你殺害無辜的女人，讓畫畫的手沾滿鮮血嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭. 큭큭. 죄가 없다고?","JPN":"クッ、ククッ。罪がない？","ENG":"Ke. Keke. Innocent?","TWN":"咳，咳咳。你說無辜？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"탐정. 당신은 진실을 꿰뚫어 보는 냉철한 이성을 가졌지만, 역시 거기까지로군.","JPN":"探偵。あんたは真実を見抜く冷徹な理性を持ってるが、やはりそこまでだな。","ENG":"Detective. You might have the rationale to see through the truth, but that's all.","TWN":"偵探。你有洞察真相的冷靜理性，但也只能到此為止了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 당신이라도 모든 걸 알지는 못해.","JPN":"いくらあんたでもすべてを知ることなんてできない。","ENG":"Even you can't know everything.","TWN":"即使是你，也不可能知道一切。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"모든 건, 내가 원해서 내린 선택이었을 뿐이야.","JPN":"すべては、私が望んで下した選択だ。","ENG":"All of this has happened because I wanted it to.","TWN":"這一切，都是我自己選擇的結果。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"내 각본에 단 하나의 실수가 있다면…….","JPN":"私の脚本にただ一つミスがあったとしたら……","ENG":"If there is one mistake in my script...","TWN":"如果我的劇本中有一處錯誤……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그건, 동생을 닮은 저 아이에게 너무 정을 붙이고 말았다는 거겠지.","JPN":"それは、妹に似たあの子に、いつの間にか情を移してしまったこと。","ENG":"it will be that I got too attached to her because she resembles too much of my sister.","TWN":"那就是，我對那個如同我妹妹一般的孩子產生了太深的感情吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"어차피 가짜 신분을 통한, 찰나의 꿈이었을 뿐인데…….","JPN":"どうせ偽の身分で見た、束の間の夢だったのに……","ENG":"After all, this is all but a fleeting dream I made with a fake identity...","TWN":"反正只是藉由假身份，所做的短暫的夢而已……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"카넬리안…….","JPN":"カーネリアン……","ENG":"Carnelian...","TWN":"卡內利安……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이제 와서 달라지는 건 아무것도 없어.","JPN":"でも今更何も変わらない。","ENG":"Nothing will change that.","TWN":"但現在已經沒有什麼會改變了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"내 앞을 가로막는다면, 천사의 강림을 방해한다면…….","JPN":"私の前に立ちはだかるなら、天使の降臨を邪魔するなら……","ENG":"If anyone stands in my way and tries to stop the angel's descent...","TWN":"若敢擋在我面前，若敢阻礙天使降臨……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"누구든 죽일 뿐이다.","JPN":"どんな奴であろうと殺すだけだ。","ENG":"only death will be waiting for them.","TWN":"無論是誰，死亡將會是他唯一的結局。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"크아아악……!!","JPN":"グアァァッ……！！","ENG":"Aaaargh...!!","TWN":"啊啊啊啊啊……！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"범인이 저항한다!! 발포해!!","JPN":"犯人が抵抗する！！　発砲しろ！！","ENG":"She's resisting!! FIRE!!","TWN":"犯人正在反抗！！開火！！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"친구, 방법이 없네! 도주하기 전에 사살해야 해!","JPN":"友よ、もう手がない！　逃走する前に射殺すべきだ！","ENG":"My friend, there is no other way! We must kill her before she gets away!","TWN":"朋友，沒別的辦法了！在她逃跑之前必須先擊斃！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……그래, 애석한 일이로군. 모든 책임은 내가 지도록 하지.","JPN":"……ああ、悲しいことだ。すべては私が責任を取ろう。","ENG":"...Yes, what a pity. I will take all responsibility for this.","TWN":"……是啊，真是遺憾的事。所有責任由我來承擔吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모든 경관은, 현시간부로 심야의 살인마를 사살하라!","JPN":"全警官は、今から深夜の殺人鬼を射殺しろ！","ENG":"All officers are permitted to fire and kill the Midnight Killer as of this moment!","TWN":"所有警官，從現在起立刻擊斃午夜殺人魔！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"크윽……!! 겨우 이정도로……!!","JPN":"くっ……！！　これで……！！","ENG":"Kgh...! You can't...!!","TWN":"咳……！就這點程度……！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"겨우 이 정도로 나를 막을 수는 없어……!!","JPN":"これで私を止めると、思うな……！！","ENG":"You can't stop me with just that...!!","TWN":"憑這種程度休想阻止我……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭!! 또 너로군……!","JPN":"くっ！！　またあんたか……！","ENG":"Kgh!! It's you again...!","TWN":"咳！！又是你……！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 땅에는 이미 역병의 안개가 자욱하구나. 곧 종말이 도래할지어다.","JPN":"その地にはすでに疫病の霧が濃い。もうじき終末が到来するであろう。","ENG":"The fog of the plague is already thick in this land. The apocalypse will soon come.","TWN":"這片大地已經被瘟疫的迷霧籠罩。末日即將來臨。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 근원은 어디에 있는가, 여인이여.","JPN":"その根源はどこにあるのか、女よ。","ENG":"Where is the origin, woman?","TWN":"那根源何在，女士？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대는 태초부터 엮인 죄의 굴레에서 벗어나지 못하니.","JPN":"そなたは原初の罪の束縛から逃れられない。","ENG":"You still have not escaped the bondage of sin that bound you since its beginning.","TWN":"你從一開始就無法擺脫罪惡的枷鎖。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나의 오랜 우행에 대해 속죄하기 위해, 이 자리에서 그대의 복수를 끊어내겠다.","JPN":"だから我の古き愚行を償うため、この場でそなたの復讐を断ち切ろう。","ENG":"To atone for my long foolish actions, I shall end your revenge here.","TWN":"為了贖還我長久以來的罪行，我將在此終結你的復仇。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"검은 갑옷……?","JPN":"黒い鎧……？","ENG":"Black armor...?","TWN":"黑色盔甲……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군. 자네가 말한 검은 갑옷의 기사가 저자로군.","JPN":"そうか。君が話していた黒い鎧の騎士はあの者だったんだな。","ENG":"I see. So that is the black armor you mentioned before.","TWN":"原來如此。你說的穿著黑色盔甲的騎士就是這個人啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 저자는 처음부터 이 사태를 막으려고 움직이고 있었겠지.","JPN":"おそらくあの者は最初からこの事態を止めようと行動していたんだろう。","ENG":"I assume that this being was trying to prevent this situation from the beginning.","TWN":"也許這個奇特的存在從一開始就在試圖阻止殺人魔……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐만요. 저 검은 갑옷은 인간이 아니에요. ","JPN":"待ってください。あの黒い鎧は人間じゃないんです。 ","ENG":"Hold on. That black armor is no human.","TWN":"等一下。那副黑色盔甲的好像不是人類吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이성이 없는 마물이 대체 어떻게……?","JPN":"理性のない魔物が、いったいどうやって……？","ENG":"How can a reasonless monster...","TWN":"沒有理智的怪物到底是怎麼……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊，哈啊……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"크으윽……!!","JPN":"ううっ……！！","ENG":"Ugh...!","TWN":"咳呃呃……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"끝이다. 의연히 안식을 받아들이도록 해라.","JPN":"終わりだ。毅然と安息を受け入れるがいい。","ENG":"It ends here. Accept your resolute death.","TWN":"結束了。坦然接受你的安息吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아……! 안식? 안식을 받아들이라고……?","JPN":"はあ、はあ……！　安息？　安息を受け入れろだと……？","ENG":"*Huff* *Huff* Rest? Accept my death...?","TWN":"哈啊，哈啊……！安息？讓我接受安息……？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"웃기지 마……!","JPN":"ふざけるな……！","ENG":"Don't make me laugh...!","TWN":"別說笑了……！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"지난 삼 년. 나는 줄곧 지옥속에 있었어! 이 런던이라는 지옥에 말이야……!","JPN":"三年間、私はずっと地獄にいたんだ！　このロンドンという地獄にな……！","ENG":"I have been living in this hellhole called London for the last three years...!","TWN":"過去的三年。我一直在地獄中！在這個名為倫敦的地獄中……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그 아이는 이것보다 끔찍한 고통 속에서 죽어갔을 텐데…….","JPN":"あの子はこれよりもひどい苦痛の中で死んでいったのに……","ENG":"My sister died suffering a more terrible pain than this...","TWN":"那孩子一定是在比這更痛苦的折磨中死去的……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그 죽음 조차도 이 도시의 머저리들에게 모욕당하고 있는데……!!","JPN":"その死すらもこの都市のゴミどもに侮辱されて……！！","ENG":"and that death was even insulted by the morons of this city...!!","TWN":"連死亡都被這座城市裡的蠢貨玷污了……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"내가 어떻게 안식을 받아들이겠어!","JPN":"何が安息だ！　そんなの、受け入れるものか！","ENG":"So, how am I supposed to accept my death?!","TWN":"我怎麼能接受安息呢！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"차라리 그 아이와 똑같은 저주를 나에게……!!","JPN":"いっそ私にあの子と同じ呪いを……！！","ENG":"I'd rather curse myself in the same way my sister was cursed…!!","TWN":"不如把和那孩子一樣的詛咒降到我身上……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"으윽, 으으으윽……!! 으아아아아아악……!!","JPN":"ううっ、ううううっ……！！　うわあああああ……！！","ENG":"Ergh! Ngh...!! ERRRRAAAAAGH...!!","TWN":"呃呃，呃呃呃呃……！！呃啊啊啊啊啊……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"카넬리안……!!","JPN":"カーネリアン……！！","ENG":"CARNELIAN...!!","TWN":"卡內利安……！！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"사실 그동안 나도 말하지 않은 비밀이 있어.","JPN":"実は私も今まで言わなかった秘密があるの。","ENG":"I also have a secret that I never told you.","TWN":"其實這段時間我也有一個秘密沒說。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"비밀이라고……?","JPN":"秘密……？","ENG":"A secret...?","TWN":"秘密……？"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"동생이 있었거든. 피는 이어지지 않았지만 살아있다면 네 또래 정도 됐을 거야.","JPN":"妹がいたんだ。血は繋がってないけど、生きてたらあなたと同い年くらいだと思う。","ENG":"I had a sister. Although we weren't related by blood, if she was alive, she'd be about your age.","TWN":"我有個妹妹。雖然沒有血緣關係，但如果她還活著的話，應該和你差不多大。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그 애도 이능력자였어. 그래서 잘 알고 있지.","JPN":"あの子も異能力者だったんだ。だからよくわかってる。","ENG":"She was also a Supernatural. So, I know.","TWN":"她也是個超能力者。所以我很了解。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이 썩어빠진 도시에서 그들이 어떤 취급을 당하고 있는지 말이야.","JPN":"この腐った都市で、彼らがどんな扱いをされてるのかをね。","ENG":"How this rotten city treats people like her.","TWN":"在這座腐朽的城市裡，他們會被如何對待。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"메리…….","JPN":"メリー……","ENG":"Mary...","TWN":"瑪麗……"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그 아이가 살아 있을 때, 난 아무것도 해주지 못했어. 오히려 모질게만 대하고 말았지.","JPN":"あの子が生きてた時、私は何もしてあげられなかったの。むしろきつく当たってしまった。","ENG":"When she was alive, I didn't do anything for her. I just treated her harshly.","TWN":"那孩子還活著的時候，我什麼都沒能為她做。反而對她很嚴厲。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"그러니까 그 아이를 대신해서라도, 내가 널 돕게 해줘.","JPN":"だからあの子の代わりでもいいから、私があなたの力になりたい。","ENG":"So, even if it's instead of her, let me help you.","TWN":"即使是為了那個孩子，也讓我來幫你吧。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"……스완 클레어.","JPN":"……スワン・クレア。","ENG":"...Swan Claire.","TWN":"……史旺·克萊爾。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"복수귀가 스스로 자기 심장을……?","JPN":"復讐鬼が自分の心臓を……？","ENG":"The Revenger stabbed her own heart...?","TWN":"復仇鬼竟然自己刺穿了自己的心臟……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 심장이라고?","JPN":"待て、心臓だと？","ENG":"What? Her heart?","TWN":"什麼？心臟？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"That can't be...","TWN":"難道你……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"탐정…….","JPN":"探偵……","ENG":"Detective...","TWN":"偵探……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"쿨럭……!! 당신이 모르고 있는 게 있어…….","JPN":"がはっ……！！　あんたの知らないことがある……","ENG":"*Cough* There is something you don't know...","TWN":"咳咳……！！你有些事情還不知道……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"내 몸에는 증표가 없지만…… 나 역시 사자자리에 수호성은 태양…….","JPN":"私の体に印はないけど……私もまた獅子座で、守護星は太陽……","ENG":"My body might not have a mark... but I too am a Leo. The sun...","TWN":"雖然我身上沒有印記……但我也是……獅子座……和太陽……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"커헉, 그리고…… <color=#ffd34c>금</color>이지…….","JPN":"くっ、それに……<color=#ffd34c>金</color>だ……","ENG":"Gagh...! Also... <color=#ffd34c>Gold</color>.","TWN":"咳呵，還有……<color=#ffd34c>金</color>……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스스로의 목숨으로 순례를 마치겠다는 건가…….","JPN":"自分の命で巡礼を終わらせるということか……","ENG":"Completing the pilgrimage by ending your own life...","TWN":"打算用自己的生命完成朝聖嗎……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어리석은 선택이야! 자네의 심장을 제물로 바친다고, 의식이 성공할 것 같나?","JPN":"愚かな選択だ！　君の心臓を生贄に捧げるとして、儀式が成功するとでも思っているのか？","ENG":"What a foolish choice! Do you think offering your heart will complete the ritual?","TWN":"太愚蠢了！你以為獻上你的心臟，儀式就會成功嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 글쎄……?","JPN":"ふふ、それはどうかな……？","ENG":"Haha, I don’t know.","TWN":"呵……呵，我還真的不知道……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이걸로 그 아이가 만족한다면…….","JPN":"でもこれであの子が満足するなら……","ENG":"But if this satisfies her...","TWN":"不過，如果這樣能讓那孩子滿意的話……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"나는 설령 내 목숨이라도…….","JPN":"私は自分の命でも……","ENG":"then even if it means my life...","TWN":"哪怕是我的生命……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"……죽었어.","JPN":"……死んだ。","ENG":"...She's dead.","TWN":"……她死了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"친구, 그러면 이제 모든 게 끝난 건가? 그 의식이라는 건 어떻게 된 거지?","JPN":"友よ、これですべてが終わったのか？　儀式とやらはどうなる？","ENG":"My friend, is it all over now? Then what happens to the ritual?","TWN":"我的朋友，現在這一切都結束了嗎？那個儀式怎麼樣了？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"조건이 맞지 않아 실패했겠지.","JPN":"条件が満たされず、失敗に終わったんだろう。","ENG":"It would've failed as the conditions weren't met.","TWN":"條件不符，應該是失敗了吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 단순히 의식을 저지하는 것만으로는 막을 수 없었던 모양이로군…….","JPN":"だが、単に儀式を阻止するだけでは止められなかったようだな……","ENG":"But it seems that simply preventing the ritual wasn't enough to stop it...","TWN":"但似乎僅僅阻止儀式是不夠的……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"결국, 이 세계에도 도래하고 마는가.","JPN":"結局、この世界にも到来してしまうのか。","ENG":"So... they descend even in this world.","TWN":"最終，這個世界也在劫難逃。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종언의 수호자들이.","JPN":"終焉の守護者たちが。","ENG":"The Guardians of Downfall.","TWN":"終焉的守護者們……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하하. 그동안 무수한 사건들을 해결해왔는데…….","JPN":"は、はは……今まで数々の事件を解決してきたが……","ENG":"Ha, haha. I've solved countless cases thus far...","TWN":"哈——哈哈。我曾解決了無數的案件……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그 결과가 애석하게도 이거로군.","JPN":"残念ながらその結果がこれか。","ENG":"It's unfortunate the outcome is this.","TWN":"結果竟然是這樣，真是遺憾。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 대체 무슨 일이 일어나려는 거죠?","JPN":"アバーライン、いったい何が起こってるんですか？","ENG":"Abberline, what's going to happen now?","TWN":"艾伯林，到底要發生什麼了？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그동안 표면 장력으로 버티고 있던 물컵 안의 내용물이 결국 넘쳐 흘러 버린 거지.","JPN":"今まで表面張力で耐えていたコップの中身が、結局は溢れだしてしまったんだ。","ENG":"The water in the cup that had been holding on due to the surface tension will eventually overflow.","TWN":"一直以來，水杯裡靠著表面張力支撐的水終於要溢出來了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 이 경우에는 컵 자체가 깨져버렸다는 게 더 알맞은 비유겠군.","JPN":"いや、この場合にはコップ自体が割れたと言った方が正しいだろう。","ENG":"No, this case would be better phrased as the cup being broken.","TWN":"不，這種情況下，杯子本身快碎了才是更合適的比喻。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 이 세계라는 컵이 말이야.","JPN":"もちろん、この世界というコップがな。","ENG":"Of course, by cup, I mean this world.","TWN":"當然，我指的是這個世界的杯子。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 무슨……!?","JPN":"それはどういう……！？","ENG":"What...?!","TWN":"你到底在打什麼啞謎……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"저, 저 괴물은 대체……!? 이쪽을 보고 있어……!?","JPN":"な、何だあの化け物は……！？　こっちを見てるぞ……！？","ENG":"Th-that monster...! It's looking toward us...?!","TWN":"那、那個怪物到底是……！？它在看這邊……！?"},"stage":{"bg":"SWANSONG_03","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"아무것도 없는 밤하늘에서 무언가가 공간을 찢고 나타나고 있어……!!","JPN":"何もない夜空から、何者かが空間を切り裂いて出てこようとしている……！！","ENG":"Something is tearing through the empty night sky...!!","TWN":"那、那裡！有什麼東西撕裂了空無一物的夜空……！！"},"stage":{"bg":"SWANSONG_03","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모든 경관들은 듣게! 지금 즉시 이 자리에서 이탈하도록!","JPN":"全警官に告げる！　直ちにこの場から離れろ！","ENG":"Attention all officers! Leave this place immediately!","TWN":"所有警員聽令！立即從這裡撤離！"},"stage":{"bg":"SWANSONG_03","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마석탄도 소용없어! 저건 인간이 어쩔 수 있는 상대가 아니야……!!","JPN":"魔石弾も無駄だ！　あれは人間がどうこうできる相手ではない……！！","ENG":"The Mana bullets will be useless! That is something humans can't do anything about...!","TWN":"魔石彈也沒用！那不是人類能對付的對手……！！"},"stage":{"bg":"SWANSONG_03","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 세계의 인간들이여.","JPN":"この世界の人間たちよ。","ENG":"Humans of this world.","TWN":"這個世界的人們啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"저것이 차원을 완전히 깨고 나타나기 전에 대피하라.","JPN":"あれが次元を完全に裂いて現れる前に避難しろ。","ENG":"Evacuate before that thing completely breaks through the dimension.","TWN":"在它完全打破次元出現之前，撤離吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그리고 살 수 있을 때까지 살거라.","JPN":"そして生き抜くのだ。息絶えるその時まで。","ENG":"And live for as long as you can.","TWN":"然後，活下去。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 어떻게 할 생각이지?","JPN":"君はどうするつもりだね？","ENG":"What are you going to do?","TWN":"你打算怎麼做？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 또한 나의 우행에서 비롯된 죄. 그렇다면 마지막까지 속죄할 뿐.","JPN":"これもまた我の愚行による罪。なら償い続けるまでだ。","ENG":"This is also a sin that stems from my foolishness. All I can do is atone until the end.","TWN":"這也是我愚行所致的罪孽。我會贖罪到最後。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……알겠네.","JPN":"……わかった。","ENG":"...Very well.","TWN":"……好吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러면 여기는 자네에게 맡기도록 하지.","JPN":"では、ここは君に任せるとしよう。","ENG":"Then, I leave this place to you.","TWN":"那這裡就交給你了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"부디 무운을 빌겠네. 검은 갑옷.","JPN":"どうかご武運を。黒い鎧。","ENG":"I bid you good luck, black armor.","TWN":"祝你好運，黑甲的騎士。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐만요, 애버라인! 지금 어디 가는 건데요? 저 괴물은 또 뭐고요……!?","JPN":"待ってください、アバーライン！　今どこに向かってるんですか？　それにあの化け物はなんですか……！？","ENG":"Wait, Abberline! Where are we going? And what is that monster...?!","TWN":"等一下，艾伯林！你現在要去哪？那怪物又是什麼……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"설명해 줄 시간이 없어! 저건…….","JPN":"説明する時間はない！　あれは……","ENG":"There's no time to explain! That's...","TWN":"沒時間解釋了！那是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저건!? <color=#ffd34c>천사</color>잖아……?","JPN":"あれは……！？　<color=#ffd34c>天使</color>……？","ENG":"That's?! An <color=#ffd34c>angel</color>...?","TWN":"那是……<color=#ffd34c>天使</color>嗎……？"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 저건 천사 같은 게 아니라네.","JPN":"いや、あれは天使なんかではない。","ENG":"No, that is no angel.","TWN":"不，那可不是天使。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"임계치를 넘은 세계가 스스로를 수호하기 위해 끌어들인 마지막 방어기제지.","JPN":"臨界値を越えた世界が、自らを守るために引き寄せた最後の防衛機制だ。","ENG":"It is the world's last defense mechanism summoned by a world that has passed the critical point to protect itself.","TWN":"那是超越臨界值的世界為了自我保護而引入的最後防禦機制。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"스스로를 수호한다고요? 무엇으로부터……?","JPN":"自らを守る？　何から……？","ENG":"To protect itself? From what...?","TWN":"自我保護？從什麼中保護……？"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"동시에 세계라는 무대를 끝내 버리기 위해 나타난 <color=#ffd34c>거짓된 신</color>.","JPN":"同時に世界という舞台の幕を閉じるために現われた<color=#ffd34c>偽りの神</color>。","ENG":"At the same time, it is the <color=#ffd34c>false god</color> that has appeared to end the stage called the world.","TWN":"也為了終結世界這個舞台而出現的<color=#ffd34c>虛偽的神</color>。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이른바, <color=#ffd34c>데우스 엑스 마키나</color>라고 할 수 있겠지.","JPN":"いわゆる、<color=#ffd34c>デウス・エクス・マキナ</color>だとも言えるだろう。","ENG":"You could call it, <color=#ffd34c>Deus ex machina</color>.","TWN":"就是所謂的，<color=#ffd34c>機械降神</color>吧。"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"데우스 엑스 마키나……?","JPN":"デウス・エクス・マキナ……？","ENG":"Deus ex machina...?","TWN":"機械降神……?"},"stage":{"bg":"WHITE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};